    elseif fromData.buffEffect then
        self.buffEffect = LBattleBuffEffectData:new(fromData.buffEffect)
    end
    ---@type LBattleTreatEffectData 治疗效果
    self.treatEffect = nil
    if fromData.HasField then
        self.treatEffect = fromData:HasField("treatEffect") and LBattleTreatEffectData:new(fromData.treatEffect) or nil
    elseif fromData.treatEffect then
        self.treatEffect = LBattleTreatEffectData:new(fromData.treatEffect)
    end
    ---@type LBattleShieldEffectData 护盾效果
