    self.shieldHurtEffect = nil
    if fromData.HasField then
        self.shieldHurtEffect = fromData:HasField("shieldHurtEffect") and LBattleShieldHurtEffectData:new(fromData.shieldHurtEffect) or nil
    elseif fromData.shieldHurtEffect then
        self.shieldHurtEffect = LBattleShieldHurtEffectData:new(fromData.shieldHurtEffect)
    end
    ---@type LBattlePShieldEffectData 格挡盾效果
    self.pShieldEffect = nil
    if fromData.HasField then
        self.pShieldEffect = fromData:HasField("pShieldEffect") and LBattlePShieldEffectData:new(fromData.pShieldEffect) or nil
    elseif fromData.pShieldEffect then
