    if fromData.HasField then
        self.angerEffect = fromData:HasField("angerEffect") and LBattleAngerEffectData:new(fromData.angerEffect) or nil
    elseif fromData.angerEffect then
        self.angerEffect = LBattleAngerEffectData:new(fromData.angerEffect)
    end
    ---@type LBattlePositionEffectData 位置效果
    self.positionEffect = nil
    if fromData.HasField then
        self.positionEffect = fromData:HasField("positionEffect") and LBattlePositionEffectData:new(fromData.positionEffect) or nil
    elseif fromData.positionEffect then
        self.positionEffect = LBattlePositionEffectData:new(fromData.positionEffect)
    end

    ---@type LBattleSelectEffectData 选中效果
    self.selectEffect = nil

    if fromData.HasField then
        if fromData:HasField("summonEffect") and fromData.summonEffect.buffSid and fromData.summonEffect.buffSid > 0 then
            self.summonEffect =  LBattleSummonEffectData:new(fromData.summonEffect)
        end
