function LBattleBaseEffectData:ToJsonTable()
    local jsonTab = {}

    jsonTab.aId = self.aId
    jsonTab.eId = self.eId
    jsonTab.type = self.type
    jsonTab.targetType = self.targetType
    jsonTab.hitType = self.hitType
    jsonTab.hurtEffect = self.hurtEffect and self.hurtEffect:ToJsonTable() or nil
    jsonTab.buffEffect = self.buffEffect and self.buffEffect:ToJsonTable() or nil
    jsonTab.treatEffect = self.treatEffect and self.treatEffect:ToJsonTable() or nil
    jsonTab.shieldEffect = self.shieldEffect and self.shieldEffect:ToJsonTable() or nil
    jsonTab.shieldHurtEffect = self.shieldHurtEffect and self.shieldHurtEffect:ToJsonTable() or nil
    jsonTab.pShieldEffect = self.pShieldEffect and self.pShieldEffect:ToJsonTable() or nil
    jsonTab.angerEffect = self.angerEffect and self.angerEffect:ToJsonTable() or nil
    jsonTab.positionEffect = self.positionEffect and self.positionEffect:ToJsonTable() or nil
    jsonTab.selectEffect = self.selectEffect and self.selectEffect:ToJsonTable() or nil
    jsonTab.summonEffect = self.summonEffect and self.summonEffect:ToJsonTable() or nil
    jsonTab.roundEffect = self.roundEffect and self.roundEffect:ToJsonTable() or nil

    return jsonTab
end

