---@class LFightBoutActionData 小回合的行动数据
local LFightBoutActionData = classX("LFightBoutActionData", nil)

local _WARNING_CNT = 50

--- 小回合的行动数据
function LFightBoutActionData:ctor(fromData)
    ---@type string 行动单位id
    self.aId = tostring(fromData.aId)
    ---@type string 行动单位id
    self.eId = tostring(fromData.eId)
    ---@type number 技能id
    self.skill = fromData.skill
    ---@type number 技能表现id
    self.express = fromData.express

    ---@type LBattleEffectArrayData[] 效果组数据集合
    self.effectArrays = {}

    local effect = fromData.effect

    if effect then
        for k,v in ipairs(effect) do
            local effectArray = LBattleEffectArrayData:new(v)
            table.insert(self.effectArrays, effectArray)
        end
    end

    self.eIdTarList = {}
end

function LFightBoutActionData:CheckLifeState(lifeState)
    local ref = GameTable.SnakeSkillRef[self.skill]
    if ref and ref.revive > 0 then
        local tmpMap = lifeState[self.aId]
        if not tmpMap then
            tmpMap = {}
            lifeState[self.aId] = tmpMap
        end
        tmpMap[ref.revive] = true
    end
end

function LFightBoutActionData:ToJsonTable()
    local jsonTab = {}
    jsonTab.aId = self.aId
    jsonTab.eId = self.eId
    jsonTab.skill = self.skill
    jsonTab.express = self.express
    jsonTab.effect = {}
    for i, v in ipairs(self.effectArrays) do
        table.insert(jsonTab.effect, v:ToJsonTable())
    end
    return jsonTab
end

---@return boolean 判断是否连击
function LFightBoutActionData:CheckIsAllbo()
    local needShowNum = 0
    local eIdTarList = self:GetEffectList()
    if #eIdTarList < 1 then return false,needShowNum end

    local isAllbo = true
    local aId = self:GetAttackId()
    for i,v in ipairs(eIdTarList) do
        if not isAllbo then break end
        for _i,_v in ipairs(v) do
            if not isAllbo then break end
            for __i,effect in ipairs(_v.list) do
                if effect.type == LFightConst.ACTIONEFFECTENUM_HURT then
                    local isOk = effect.hitType == 1
                    if isOk then
                        if aId ~= effect.aId then
                            isAllbo = false
                            break
                        else
                            needShowNum = needShowNum + 1
                        end
                    end
                end
            end
        end
    end
    if needShowNum == 1 then
        isAllbo = false
    end
    return isAllbo,needShowNum
end

---@return boolean
function LFightBoutActionData:CheckIsAttack()
    local eIdTarList = self:GetEffectList()
    if #eIdTarList < 1 then return false end

    local skillId = self:GetSkill()
    if not skillId or skillId < 1 then return false end

    local aId = self.aId
    local bAttack = false
    local needShowType = {
        [LFightConst.ACTIONEFFECTENUM_HURT] = true,
        [LFightConst.ACTIONEFFECTENUM_TREATS] = true,
    }
    for i,v in ipairs(eIdTarList) do
        if bAttack then break end
        for _i,_v in ipairs(v) do
            if bAttack then break end
            for __i,effect in ipairs(_v.list) do
                if needShowType[effect.type] and effect.hitType == 1 then
                    if aId == effect.aId then
                        bAttack = true
                        break
                    end
                end
            end
        end
    end
    return bAttack
end

