    jsonTab.list = {}
    for i, v in ipairs(self.list) do
        table.insert(jsonTab.list, v:ToJsonTable())
    end
    return jsonTab
end

---@class LFightBoutData 出手回合数据（小回合 单个英雄的出手
local LFightBoutData = classX("LFightBoutData", nil)
---出手回合数据（小回合 单个英雄的出手
function LFightBoutData:ctor()
    ---@type string 出手英雄id
    self.aId = '0'

    ---@type number 使用的技能refId
    self.skill = 0

    ---@type LBattleBoutActionListData[]
    self.actions = {}

    ---@type number
    self.actionTotalCount = 0
end

function LFightBoutData:ToJsonTable()
    local jsonTab = {}
    jsonTab.aId = self.aId
    jsonTab.skill = self.skill
    jsonTab.actions = {}
    for i, v in ipairs(self.actions) do
        table.insert(jsonTab.actions, v:ToJsonTable())
    end
    return jsonTab
end

function LFightBoutData:InitData(fromData, lifeState)
    self.aId = tostring(fromData.aId)
    self.skill = fromData.skill

    self.actions = {}
    local actions = fromData.actions
    if actions then
        for k,v in ipairs(actions) do
            local actionList = LBattleBoutActionListData:new(v, lifeState)
            table.insert(self.actions, actionList)
        end
    end
    self.actionCount = #actions
    self.actionTotalCount = self.actionCount
end

function LFightBoutData:GetAction(actionIdx)
    return self.actions[actionIdx]
end

function LFightBoutData:GetActionTotalCount()
    return self.actionTotalCount
end

function LFightBoutData:HasAction(actionIdx)
    return (self.actions[actionIdx] ~= nil)
end

return LFightBoutData